import React, { FunctionComponent, useState } from "react";
import { H1, H6 } from "@blueprintjs/core";
import { observer } from "mobx-react";

export const PendingAwaiting: FunctionComponent = observer(() => {
  return (
    <div className="body">
      <div className="connected-body">
        <div className="curve-border">
          <div className="fx -c center">
            <H1 className="title-primary">Welcome to Heabank !</H1>
            <H6 className="title-primary">
              Hello dear customer, to finalize your registration, please fill in
              the various fields below. A banker will then be in charge of your
              file in order to process your registration request. You will be
              able to reconnect whenever you want to follow the status of your
              application.
            </H6>
          </div>
        </div>
      </div>
    </div>
  );
});
